 1	import {
 2	  DatePicker,
 3	  InputGroup,
 4	  InputGroupItem,
 5	  isValidDate,
 6	  TimePicker,
 7	  yyyyMMddFormat,
 8	} from '@patternfly/react-core';
 9	import * as React from 'react';
10	import { copyTime, setTime } from '../time';
11	
12	/** Combine date and time pickers, return the result as a Date */
13	export const DateTimePicker: React.FC<{
14	  date: Date;
15	  onChange: (date: Date) => void;
16	}> = ({ date, onChange }) => {
17	  if (!isValidDate(date)) date = new Date();
18	  return (
19	    <InputGroup>
20	      <InputGroupItem>
21	        <DatePicker
22	          value={isValidDate(date) ? yyyyMMddFormat(date) : ''}
23	          onChange={(_event, _inputDate, newDate) => onChange(copyTime(newDate, date))}
24	        />
25	      </InputGroupItem>
26	      <InputGroupItem>
27	        <TimePicker
28	          time={date}
29	          onChange={(_event, _time, hour, minute, second, isValid) => {
30	            if (isValid) onChange(setTime(date, hour, minute, second));
31	          }}
32	          is24Hour={true}
33	          width="80px"
34	        />
35	      </InputGroupItem>
36	    </InputGroup>
37	  );
38	};

